// --- Variables de prueba ---
const cliente = "Andrea Perez";
const descripcionGeneral = "Descripción de la cotización";
const codigoProducto = "SH229";
const descripcionProducto = "Descripción adicional del producto";
const cantidad = "2";
const modalSelector = ".cotizacion-modal"; // <--- si cambia el modal, solo cambias aquí
// --- Ir al módulo de Ingresos ---
cy.visit("/ingresos");
cy.url().should("include", "/ingresos");
// --- Abrir modal de Cotización ---
cy.get('a[onclick="openCotizacionModal()"]').click();
// --- Trabajar dentro del modal ---
cy.get(modalSelector).should("be.visible").within(() => {
  // --- Cliente ---
  cy.get('input[name="cliente"]').type(cliente);
  // --- Descripción general ---
  cy.get('input[name="descripcion"]').type(descripcionGeneral);
  // --- Producto ---
  cy.get(".custom-select-container").first().click();
  cy.get(".custom-select-container.open .custom-select-options").contains("li.custom-select-option", codigoProducto).click();
  // ---Descripción adicional ---
  cy.get("input.form-control.descripcion-input").clear().type(descripcionProducto);
  // ---Cantidad ---
  cy.get("input.form-control.cantidad-input").clear().type(cantidad);
  // ---Guardar ---
  cy.get("div.cotizacion-modal__footer button.btn.btn-primary").click();
});
